{
  "name": "BookMyDoctor Premium",
  "description": "Premium healthcare marketplace for finding and booking verified doctors with real-time availability.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React, { useState } from 'react';
import { Search, MapPin, ShieldCheck, CheckCircle2, ChevronDown, Activity, Users, Star } from 'lucide-react';
import { Button } from './Button';
import { LOCATIONS, INSURANCE_PROVIDERS } from '../constants';
import { FilterState } from '../types';

interface HeroProps {
  onSearch: (filters: FilterState) => void;
}

export const Hero: React.FC<HeroProps> = ({ onSearch }) => {
  const [location, setLocation] = useState('');
  const [query, setQuery] = useState('');
  const [insurance, setInsurance] = useState('');
  const [availability, setAvailability] = useState<'any' | 'today'>('any');

  const handleManualSearch = (e: React.FormEvent) => {
    e.preventDefault();
    onSearch({ location, query, specialty: '', insurance, availability });
  };

  return (
    <div className="relative bg-white pt-12 pb-24 lg:pt-20 lg:pb-32 overflow-hidden">
      {/* Dynamic Background Elements */}
      <div className="absolute top-0 right-0 -mr-40 -mt-40 w-[600px] h-[600px] bg-brand-50 rounded-full blur-[120px] opacity-60 z-0"></div>
      <div className="absolute -bottom-40 -left-40 w-[500px] h-[500px] bg-brand-50 rounded-full blur-[120px] opacity-40 z-0"></div>

      <div className="relative z-10 max-w-7xl mx-auto px-6 sm:px-8">
        <div className="text-center max-w-4xl mx-auto mb-16">
          <div className="inline-flex items-center gap-3 bg-white text-brand-700 px-5 py-2.5 rounded-full text-xs font-black uppercase tracking-widest mb-8 animate-fade-in shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-slate-50">
            <Activity className="w-4 h-4 text-brand-500" />
            <span>Dubai's Elite Medical Marketplace</span>
          </div>
          <h1 className="text-5xl sm:text-7xl lg:text-8xl font-black text-slate-900 tracking-tighter leading-[0.95] mb-8">
            Health Care <br/><span className="text-brand-600">Perfected.</span>
          </h1>
          <p className="text-xl sm:text-2xl text-slate-500 font-medium leading-relaxed mb-12 max-w-2xl mx-auto">
            Book top-tier specialists with real-time availability in Dubai. Instant confirmation via WhatsApp & SMS.
          </p>

          <div className="flex flex-wrap justify-center gap-6 mb-16">
             <div className="flex items-center gap-2 text-sm font-bold text-slate-600 bg-slate-50 px-4 py-2 rounded-2xl">
                <Users className="w-4 h-4 text-brand-500" /> 50k+ Bookings
             </div>
             <div className="flex items-center gap-2 text-sm font-bold text-slate-600 bg-slate-50 px-4 py-2 rounded-2xl">
                <Star className="w-4 h-4 text-amber-500 fill-amber-500" /> 4.9/5 Rating
             </div>
          </div>
        </div>

        {/* Enhanced Search Container */}
        <div className="max-w-6xl mx-auto">
          <div className="bg-white rounded-[40px] shadow-[0_32px_80px_-20px_rgba(13,148,136,0.15)] border border-slate-100 p-4 lg:p-6 transition-all hover:shadow-[0_32px_80px_-10px_rgba(13,148,136,0.2)]">
            <form onSubmit={handleManualSearch} className="flex flex-col gap-5">

              {/* Main Search */}
              <div className="relative group flex-grow">
                <div className="absolute inset-y-0 left-0 pl-6 flex items-center pointer-events-none">
                  <Search className="h-6 w-6 text-slate-300 group-focus-within:text-brand-600 transition-colors" />
                </div>
                <input
                  type="text"
                  className="block w-full pl-16 pr-6 py-6 bg-slate-50 border-none rounded-[28px] focus:ring-4 focus:ring-brand-100 text-slate-900 placeholder:text-slate-400 font-black text-xl h-20 transition-all outline-none"
                  placeholder="Specialty, doctor name, or clinic..."
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                />
              </div>

              {/* Filters & Action */}
              <div className="grid grid-cols-1 lg:grid-cols-4 gap-4">

                {/* Location Select */}
                <div className="relative group h-16">
                  <div className="absolute inset-y-0 left-0 pl-6 flex items-center pointer-events-none">
                    <MapPin className="h-5 w-5 text-slate-300" />
                  </div>
                  <select
                    className="block w-full h-full pl-14 pr-10 bg-slate-50 border-none rounded-[24px] focus:ring-4 focus:ring-brand-100 text-slate-700 appearance-none cursor-pointer font-bold text-sm outline-none"
                    value={location}
                    onChange={(e) => setLocation(e.target.value)}
                  >
                    <option value="">Any Area in Dubai</option>
                    {LOCATIONS.map(loc => <option key={loc} value={loc}>{loc}</option>)}
                  </select>
                  <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-300" />
                </div>

                {/* Insurance Select */}
                <div className="relative group h-16">
                  <div className="absolute inset-y-0 left-0 pl-6 flex items-center pointer-events-none">
                    <ShieldCheck className="h-5 w-5 text-slate-300" />
                  </div>
                  <select
                    className="block w-full h-full pl-14 pr-10 bg-slate-50 border-none rounded-[24px] focus:ring-4 focus:ring-brand-100 text-slate-700 appearance-none cursor-pointer font-bold text-sm outline-none"
                    value={insurance}
                    onChange={(e) => setInsurance(e.target.value)}
                  >
                    <option value="">Insurance Provider</option>
                    {INSURANCE_PROVIDERS.map(i => <option key={i} value={i}>{i}</option>)}
                  </select>
                  <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-300" />
                </div>

                {/* Availability Toggle */}
                <div 
                  className="relative flex items-center justify-between bg-slate-50 rounded-[24px] px-6 h-16 cursor-pointer hover:bg-slate-100 transition-colors" 
                  onClick={() => setAvailability(availability === 'any' ? 'today' : 'any')}
                >
                  <span className="text-sm font-black text-slate-600">Available Today</span>
                  <div className={`w-12 h-7 rounded-full transition-all flex items-center p-1 ${availability === 'today' ? 'bg-brand-600 shadow-lg shadow-brand-200' : 'bg-slate-200'}`}>
                    <div className={`w-5 h-5 bg-white rounded-full shadow-sm transition-transform ${availability === 'today' ? 'translate-x-5' : 'translate-x-0'}`}></div>
                  </div>
                </div>

                {/* CTA Button */}
                <Button type="submit" size="lg" className="h-16 text-lg font-black tracking-wider bg-brand-600 hover:bg-brand-700 shadow-2xl shadow-brand-200 transition-all rounded-[24px] hover:-translate-y-1 active:scale-[0.98]">
                  FIND DOCTORS
                </Button>
              </div>
            </form>
          </div>
        </div>

        {/* Benefits text */}
        <div className="mt-20 flex flex-wrap justify-center gap-10">
          {[
            { label: "SMS/WhatsApp Confirmed", icon: Activity },
            { label: "100% Verified Profiles", icon: ShieldCheck },
            { label: "No Booking Fees", icon: CheckCircle2 }
          ].map((item, i) => (
            <div key={i} className="flex items-center gap-3 text-slate-400 font-black text-[10px] uppercase tracking-[0.2em]">
               <item.icon className="w-5 h-5 text-brand-500" />
               {item.label}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Doctor } from '../types';
import { Star, MapPin, ThumbsUp, ShieldCheck, Globe, CreditCard, Users, Search, Building2, Clock, CalendarCheck } from 'lucide-react';
import { Button } from './Button';

interface DoctorListProps {
  doctors: Doctor[];
  onBook: (doctor: Doctor) => void;
}

export const DoctorList: React.FC<DoctorListProps> = ({ doctors, onBook }) => {
  if (doctors.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-24 bg-slate-50/50 rounded-[48px] border-4 border-dashed border-slate-100">
        <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center mb-6 shadow-xl shadow-slate-200/50">
           <Search className="w-10 h-10 text-slate-200" />
        </div>
        <h3 className="text-3xl font-black text-slate-900 tracking-tight">No specialists found</h3>
        <p className="text-slate-400 mt-2 font-bold max-w-xs text-center">Try adjusting your filters or search criteria for more results.</p>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      {doctors.map((doctor) => (
        <div key={doctor.id} className="group bg-white rounded-[48px] border border-slate-100 p-8 shadow-[0_8px_30px_rgb(0,0,0,0.02)] hover:shadow-[0_32px_60px_-15px_rgba(13,148,136,0.12)] hover:border-brand-100 transition-all duration-700 flex flex-col md:flex-row gap-10 relative overflow-hidden">

          {/* Subtle accent bar */}
          {doctor.isVerified && (
            <div className="absolute top-0 left-0 w-2 h-full bg-gradient-to-b from-brand-500 to-brand-700"></div>
          )}

          {/* Left Column: Media & Trust */}
          <div className="flex-shrink-0 flex flex-col items-center">
            <div className="relative mb-6">
              <img 
                src={doctor.image} 
                alt={doctor.name} 
                className="h-44 w-44 rounded-[40px] object-cover border-4 border-white shadow-2xl group-hover:scale-105 transition-transform duration-700"
              />
              {doctor.isVerified && (
                <div className="absolute -bottom-2 -right-2 bg-brand-600 p-2.5 rounded-2xl border-4 border-white shadow-xl text-white">
                   <ShieldCheck className="w-6 h-6" />
                </div>
              )}
            </div>

            <div className="flex flex-col gap-2.5 w-full">
               <div className="flex items-center justify-center gap-2 bg-brand-50 text-brand-700 px-4 py-2 rounded-2xl text-[10px] font-black uppercase tracking-widest border border-brand-100">
                  <ThumbsUp className="w-3.5 h-3.5" />
                  <span>98% Patient Approval</span>
               </div>
               <div className="flex items-center justify-center gap-2 bg-slate-50 text-slate-400 px-4 py-2 rounded-2xl text-[10px] font-black uppercase tracking-widest border border-slate-100">
                  <Users className="w-3.5 h-3.5" />
                  <span>{doctor.totalBookings}+ Booked</span>
               </div>
            </div>
          </div>

          {/* Main Info Column */}
          <div className="flex-1 flex flex-col">
            <div className="flex flex-col xl:flex-row justify-between items-start gap-6 mb-8">
              <div className="space-y-4">
                <div>
                  <h3 className="text-4xl font-black text-slate-900 group-hover:text-brand-700 transition-colors leading-tight mb-1">
                    {doctor.name}
                  </h3>
                  <div className="flex flex-wrap items-center gap-3">
                    <span className="px-3 py-1 bg-brand-100 text-brand-700 rounded-lg text-[10px] font-black uppercase tracking-widest">
                      {doctor.specialty}
                    </span>
                    <div className="h-1 w-1 rounded-full bg-slate-300"></div>
                    <div className="flex items-center gap-2 text-slate-400 font-bold text-sm">
                      <Building2 className="w-4 h-4" />
                      {doctor.clinicName}
                    </div>
                  </div>
                </div>

                <div className="flex items-center gap-6">
                   <div className="flex items-center gap-1.5 bg-amber-50 text-amber-700 px-4 py-1.5 rounded-xl text-sm font-black shadow-sm border border-amber-100">
                      <Star className="w-4 h-4 fill-amber-400 text-amber-400" />
                      {doctor.rating}
                   </div>
                   <button className="text-slate-400 text-xs font-black uppercase tracking-widest hover:text-brand-600 transition-colors">
                     {doctor.reviews} Reviews
                   </button>
                   <span className="text-slate-400 text-xs font-black uppercase tracking-widest">{doctor.experience} Yrs Exp</span>
                </div>
              </div>

              {/* Fee Component */}
              <div className="bg-slate-50/80 p-6 rounded-[32px] border border-slate-100 min-w-[200px] text-center shadow-inner relative group/fee">
                 <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Initial Consultation</div>
                 <div className="text-4xl font-black text-slate-900">AED {doctor.fee}</div>
                 <div className="flex items-center justify-center gap-2 mt-3 text-[10px] text-brand-600 font-black tracking-widest uppercase">
                    <CalendarCheck className="w-4 h-4" /> Instant Slot
                 </div>
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-10 text-slate-500">
              <div className="flex items-start gap-3 text-sm font-bold">
                <MapPin className="w-5 h-5 text-brand-400 shrink-0" />
                <span className="leading-tight">{doctor.location}, Dubai</span>
              </div>
              <div className="flex items-start gap-3 text-sm font-bold">
                <Globe className="w-5 h-5 text-brand-400 shrink-0" />
                <span className="leading-tight">Available in: {doctor.languages.join(', ')}</span>
              </div>
            </div>

            {/* Bottom Section: Slots & Action */}
            <div className="mt-auto pt-8 border-t border-slate-100 flex flex-col xl:flex-row items-center gap-8">
               <div className="w-full xl:w-auto">
                 <div className="flex items-center gap-2 mb-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    <Clock className="w-4 h-4 text-brand-500" /> Next Available Slots
                 </div>
                 <div className="flex gap-2.5 overflow-x-auto pb-2 scrollbar-hide justify-center xl:justify-start">
                    {doctor.availableSlots.map(slot => (
                      <button 
                        key={slot}
                        onClick={() => onBook(doctor)}
                        className="whitespace-nowrap px-6 py-3 rounded-2xl border-2 border-slate-100 bg-white text-xs text-slate-700 font-black hover:bg-brand-600 hover:text-white hover:border-brand-600 transition-all active:scale-95 shadow-sm"
                      >
                        {slot}
                      </button>
                    ))}
                 </div>
               </div>
               <Button 
                onClick={() => onBook(doctor)} 
                className="w-full xl:w-auto px-12 py-6 bg-brand-600 hover:bg-brand-700 shadow-2xl shadow-brand-200 text-base font-black tracking-widest rounded-[28px] group"
               >
                 BOOK APPOINTMENT
                 <ChevronRight className="ml-2 w-6 h-6 group-hover:translate-x-1 transition-transform" />
               </Button>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

import React from 'react';
import { SPECIALTIES } from '../constants';
import * as Icons from 'lucide-react';

interface SpecialtyCardsProps {
  onSelectSpecialty: (specialty: string) => void;
}

export const SpecialtyCards: React.FC<SpecialtyCardsProps> = ({ onSelectSpecialty }) => {
  return (
    <div className="bg-white py-24">
      <div className="max-w-7xl mx-auto px-6 sm:px-8">
        <div className="flex flex-col md:flex-row justify-between items-end mb-16 gap-6">
           <div className="max-w-xl">
              <h2 className="text-[10px] font-black text-brand-600 uppercase tracking-[0.3em] mb-4">Clinical Specializations</h2>
              <h3 className="text-4xl font-black text-slate-900 tracking-tight">World-Class Care <br/>Across All Disciplines</h3>
           </div>
           <p className="text-slate-400 font-medium max-w-xs text-right hidden md:block">Select a specialty to browse our curated list of verified medical experts.</p>
        </div>

        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-6">
          {SPECIALTIES.map((specialty) => {
            const IconComponent = (Icons as any)[specialty.icon] || Icons.Activity;

            return (
              <button
                key={specialty.id}
                onClick={() => onSelectSpecialty(specialty.name)}
                className="group flex flex-col items-center justify-center p-8 rounded-[40px] bg-slate-50/50 border border-slate-100 hover:bg-white hover:border-brand-200 hover:shadow-2xl hover:-translate-y-2 transition-all duration-500 ease-out"
              >
                <div className="h-20 w-20 rounded-[24px] bg-white border border-slate-100 flex items-center justify-center shadow-sm text-brand-500 group-hover:bg-brand-600 group-hover:text-white group-hover:border-brand-600 transition-all duration-500 mb-6">
                  <IconComponent className="h-10 w-10" strokeWidth={1.5} />
                </div>
                <span className="text-sm font-black text-slate-700 group-hover:text-brand-600 text-center tracking-tight transition-colors">
                  {specialty.name}
                </span>
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
};

