import React, { useState, useMemo, useEffect } from 'react';
import { Navbar } from './components/Navbar';
import { Hero } from './components/Hero';
import { SpecialtyCards } from './components/SpecialtyCards';
import { DoctorList } from './components/DoctorList';
import { BookingModal } from './components/BookingModal';
import { SignIn } from './components/SignIn';
import { SignUp } from './components/SignUp';
import { SignUpPatient } from './components/SignUpPatient';
import { SignUpSpecialist } from './components/SignUpSpecialist';
import { SignUpClinic } from './components/SignUpClinic';
import { AskExpert } from './components/AskExpert';
import { DOCTORS as MOCK_DOCTORS, INSURANCE_PROVIDERS, LOCATIONS, SPECIALTIES } from './constants';
import { Doctor, FilterState, Page } from './types';
import { Button } from './components/Button';
import { 
  ArrowLeft, 
  Search,
  Check,
  Stethoscope,
  Facebook,
  Twitter,
  Instagram,
  ShieldCheck,
  Zap,
  MessageSquare,
  Heart,
  CalendarCheck2,
  PhoneCall,
  Clock,
  TrendingUp,
  Award,
  Calendar
} from 'lucide-react';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.HOME);
  const [filters, setFilters] = useState<FilterState>({ location: '', specialty: '', query: '', insurance: '', availability: 'any' });
  const [selectedDoctor, setSelectedDoctor] = useState<Doctor | null>(null);
  const [isBookingModalOpen, setIsBookingModalOpen] = useState(false);
  const [doctors, setDoctors] = useState<Doctor[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    // Simulate real loading for premium feel
    const timer = setTimeout(() => {
       setDoctors(MOCK_DOCTORS);
       setIsLoading(false);
    }, 800);
    return () => clearTimeout(timer);
  }, []);

  const handleNavigate = (page: Page) => {
    setCurrentPage(page);
    window.scrollTo(0, 0);
  };

  const handleSearch = (newFilters: FilterState) => {
    setFilters(newFilters);
    handleNavigate(Page.SEARCH);
  };

  const handleSelectSpecialty = (specialty: string) => {
    setFilters({ location: '', specialty, query: '', insurance: '' });
    handleNavigate(Page.SEARCH);
  };

  const handleBookClick = (doctor: Doctor) => {
    setSelectedDoctor(doctor);
    setIsBookingModalOpen(true);
  };

  const handleBookingConfirm = () => {
    setIsBookingModalOpen(false);
    handleNavigate(Page.APPOINTMENT_SUCCESS);
  };

  const filteredDoctors = useMemo(() => {
    return doctors.filter(doc => {
      const matchLoc = filters.location ? doc.location.toLowerCase().includes(filters.location.toLowerCase()) : true;
      const matchSpec = filters.specialty ? doc.specialty === filters.specialty : true;
      const matchQuery = filters.query 
        ? (doc.name.toLowerCase().includes(filters.query.toLowerCase()) || 
           doc.specialty.toLowerCase().includes(filters.query.toLowerCase()) ||
           doc.clinicName.toLowerCase().includes(filters.query.toLowerCase()))
        : true;
      const matchInsurance = filters.insurance 
        ? doc.insuranceAccepted.includes(filters.insurance)
        : true;
      return matchLoc && matchSpec && matchQuery && matchInsurance;
    });
  }, [filters, doctors]);

  return (
    <div className="min-h-screen flex flex-col font-sans text-slate-900 bg-white">
      <Navbar onNavigate={handleNavigate} currentPage={currentPage} />

      {/* Floating CTA for mobile (Conversion optimized) */}
      <div className="md:hidden fixed bottom-6 right-6 z-[90]">
         <Button 
            size="lg" 
