  useEffect(() => {
    // Simulate real loading for premium feel
    const timer = setTimeout(() => {
       setDoctors(MOCK_DOCTORS);
       setIsLoading(false);
    }, 800);
    return () => clearTimeout(timer);
  }, []);

  const handleNavigate = (page: Page) => {
    setCurrentPage(page);
    window.scrollTo(0, 0);
  };

