        ? (doc.name.toLowerCase().includes(filters.query.toLowerCase()) || 
           doc.specialty.toLowerCase().includes(filters.query.toLowerCase()) ||
           doc.clinicName.toLowerCase().includes(filters.query.toLowerCase()))
        : true;
