                            <span className="text-lg font-bold text-slate-700 group-hover:text-slate-900">{spec.name}</span>
                          </div>
                          <span className="text-xs font-black text-slate-300 uppercase tracking-widest">Specialty</span>
                        </button>
                      ))}
